#include <iostream>
#include <vector>

using namespace std;

int findJudge(int n, vector<vector<int>>& trust)
{
    vector<vector<int>> adj(n + 1);
    for (auto &t : trust) adj[t[0]].push_back(t[1]);

    for (int candidate = 1; candidate <= n; candidate++)
    {
        if (!adj[candidate].empty()) continue;

        int trustedByCount = 0;
        for (int person = 1; person <= n; person++)
        {
            if (person == candidate) continue;
            for (int trustee : adj[person])
                if (trustee == candidate) { trustedByCount++; break; }
        }
        if (trustedByCount == n - 1) return candidate;
    }
    return -1;
}

int main()
{
    vector<vector<int>> trust = {{1, 3}, {2, 3}, {3, 1}};
    cout << findJudge(3, trust);

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

int findJudge(int n, vector<vector<int>>& trust)
{
    vector<int> inDegree(n + 1, 0), outDegree(n + 1, 0);
    for (auto &t : trust)
    {
        outDegree[t[0]]++;
        inDegree[t[1]]++;
    }

    for (int person = 1; person <= n; person++)
        if (inDegree[person] == n - 1 && outDegree[person] == 0) return person;
    return -1;
}

int main()
{
    vector<vector<int>> trust = {{1, 3}, {2, 3}, {3, 1}};
    cout << findJudge(3, trust);

    return 0;
}
